public void testZeroFollowedByNonDigit() {
  assertPrint("var x ='\\0a';", "var x=\"\\0a\"");
  assertPrint("var x ='\\0z';", "var x=\"\\0z\"");
  assertPrint("var x ='\\0 ';", "var x=\"\\0 \"");
}

public void testZeroAtEndOfString() {
  assertPrint("var x ='\\0';", "var x=\"\\0\"");
  assertPrint("var x ='abc\\0';", "var x=\"abc\\0\"");
}

public void testMultipleZeros() {
  assertPrint("var x ='\\0\\0';", "var x=\"\\0\\0\"");
  assertPrint("var x ='\\01\\02';", "var x=\"\\0001\\0002\"");
}
